#include <Arduino.h>

// ===== PIN =====
#define BUTTON 13
#define LED 2

// ===== QUEUE =====
QueueHandle_t modeQueue;

// ===== TASK BUTTON =====
void TaskButton(void *pvParameters) {
  pinMode(BUTTON, INPUT_PULLUP);

  int mode = 0;
  bool lastState = HIGH;

  while (1) {
    int reading = digitalRead(BUTTON);

    if (reading == LOW && lastState == HIGH) {
      mode++;
      if (mode > 2) mode = 0;

      xQueueSend(modeQueue, &mode, portMAX_DELAY);
    }

    lastState = reading;
    vTaskDelay(pdMS_TO_TICKS(200)); // debounce đơn giản
  }
}

// ===== TASK LED =====
void TaskLED(void *pvParameters) {
  pinMode(LED, OUTPUT);

  int currentMode = 0;
  int receivedMode;

  while (1) {

    // nhận mode nếu có
    if (xQueueReceive(modeQueue, &receivedMode, 0)) {
      currentMode = receivedMode;
    }

    switch (currentMode) {

      case 0: // OFF
        digitalWrite(LED, LOW);
        vTaskDelay(pdMS_TO_TICKS(100));
        break;

      case 1: // blink 1s
        digitalWrite(LED, HIGH);
        vTaskDelay(pdMS_TO_TICKS(1000));
        digitalWrite(LED, LOW);
        vTaskDelay(pdMS_TO_TICKS(1000));
        break;

      case 2: // blink nhanh
        digitalWrite(LED, HIGH);
        vTaskDelay(pdMS_TO_TICKS(200));
        digitalWrite(LED, LOW);
        vTaskDelay(pdMS_TO_TICKS(200));
        break;
    }
  }
}

void setup() {
  Serial.begin(115200);

  modeQueue = xQueueCreate(5, sizeof(int));

}

